// Build SF enrichment updates for every Company.
// Reads ME_Account_Mirror, ME_Opportunity_Mirror, ME_Contact_Mirror laterally
// from upstream Airtable list nodes. Emits one update item per Company.

function bareDomain(url) {
  if (!url) return null;
  return String(url).toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/\/.*$/, '')
    .trim() || null;
}

function stageName(stage) {
  if (!stage) return null;
  if (typeof stage === 'string') return stage;
  if (typeof stage === 'object' && stage.name) return stage.name;
  return null;
}

const companies = $input.all().map(i => i.json);
const accounts = $('List Accounts').all().map(i => i.json);
const opps = $('List Opportunities').all().map(i => i.json);
const contacts = $('List Contacts').all().map(i => i.json);

// Build lookup maps over the SF mirrors.
const accountByDomain = new Map();
const accountByName = new Map();
const accountById = new Map();
for (const a of accounts) {
  const sfId = a['Account ID'];
  if (!sfId) continue;
  accountById.set(sfId, a);
  const dom = bareDomain(a['Website']);
  if (dom) {
    if (!accountByDomain.has(dom)) accountByDomain.set(dom, []);
    accountByDomain.get(dom).push(a);
  }
  const nm = (a['Account Name'] || '').trim().toLowerCase();
  if (nm) {
    if (!accountByName.has(nm)) accountByName.set(nm, []);
    accountByName.get(nm).push(a);
  }
}

const oppsByAccount = new Map();
for (const o of opps) {
  const aid = o['Account ID'];
  if (!aid) continue;
  if (!oppsByAccount.has(aid)) oppsByAccount.set(aid, []);
  oppsByAccount.get(aid).push(o);
}

const contactsByAccount = new Map();
for (const c of contacts) {
  const aid = c['Account ID'];
  if (!aid) continue;
  if (!contactsByAccount.has(aid)) contactsByAccount.set(aid, []);
  contactsByAccount.get(aid).push(c);
}

const now = DateTime.now();
const out = [];
const noMatchLog = [];

for (const company of companies) {
  const recordId = company.id;
  const fields = company; // company has fields at top level under cellValuesByFieldId-style flattening; n8n Airtable v2 returns cleaner shape.
  const companyName = (fields['Company Name'] || '').trim();
  const dom = bareDomain(fields['Website Domain']);

  // Match: domain first, then exact name. Skip ambiguous (multi-match).
  let match = null;
  if (dom && accountByDomain.has(dom)) {
    const candidates = accountByDomain.get(dom);
    if (candidates.length === 1) match = candidates[0];
  }
  if (!match) {
    const nm = companyName.toLowerCase();
    if (nm && accountByName.has(nm)) {
      const candidates = accountByName.get(nm);
      if (candidates.length === 1) match = candidates[0];
    }
  }

  if (!match) {
    noMatchLog.push({ recordId, companyName, dom });
    out.push({
      json: {
        id: recordId,
        'SF Record ID': '',
        'Salesforce Account ID': '',
        'Last Contacted Date': null,
        'DNC / Opt-Out': false,
        'Active SF Opportunity': false,
        'SF Opportunity Stage': '',
        'Customer Status': 'Never Customer',
        'Active BD Engagement': 'None',
        '_matched': false,
      }
    });
    continue;
  }

  const sfId = match['Account ID'];
  const oppList = oppsByAccount.get(sfId) || [];
  const contactList = contactsByAccount.get(sfId) || [];

  const lastActivityRaw = match['Last Activity'];
  const lastActivity = lastActivityRaw ? DateTime.fromISO(lastActivityRaw) : null;
  const daysSinceActivity = lastActivity ? now.diff(lastActivity, 'days').days : null;

  const openOpps = oppList.filter(o => o['Closed'] !== true);
  const wonOpps = oppList.filter(o => stageName(o['Stage']) === 'Closed Won');
  let latestWonClose = null;
  for (const o of wonOpps) {
    if (!o['Close Date']) continue;
    const d = DateTime.fromISO(o['Close Date']);
    if (!latestWonClose || d > latestWonClose) latestWonClose = d;
  }

  // Customer Status
  let customerStatus = 'Never Customer';
  if (latestWonClose) {
    customerStatus = now.diff(latestWonClose, 'months').months <= 12
      ? 'Current Customer' : 'Historical Customer';
  }

  // Active BD Engagement
  let bdEngagement = 'None';
  if (openOpps.length > 0 || (daysSinceActivity !== null && daysSinceActivity <= 30)) {
    bdEngagement = 'Active';
  } else if (oppList.length > 0 || lastActivity) {
    bdEngagement = 'Past';
  }

  // DNC / Opt-Out: any contact at this account has Do Not Call OR Email Opt Out
  const dnc = contactList.some(c => c['Do Not Call'] === true || c['Email Opt Out'] === true);

  // Active SF Opportunity + Stage
  const activeOpp = openOpps.length > 0;
  let stage = '';
  if (activeOpp) {
    const sortedOpen = openOpps.slice().sort((a, b) =>
      new Date(b['Last Modified Date'] || 0) - new Date(a['Last Modified Date'] || 0));
    stage = stageName(sortedOpen[0]['Stage']) || '';
  }

  out.push({
    json: {
      id: recordId,
      'SF Record ID': sfId,
      'Salesforce Account ID': sfId,
      'Last Contacted Date': lastActivityRaw || null,
      'DNC / Opt-Out': dnc,
      'Active SF Opportunity': activeOpp,
      'SF Opportunity Stage': stage,
      'Customer Status': customerStatus,
      'Active BD Engagement': bdEngagement,
      '_matched': true,
    }
  });
}

if (noMatchLog.length) {
  console.log(`No SF match for ${noMatchLog.length} companies:`, JSON.stringify(noMatchLog, null, 2));
}
console.log(`Built ${out.length} updates (${out.filter(x => x.json._matched).length} matched).`);
return out;
